solution.code:
def bin_to_oct(s):
    while len(s) % 3 != 0:
        s = "0" + s
    res = ""
    for i in range(0, len(s), 3):
        triplet = s[i:i+3]
        res += str(int(triplet, 2))
    return res

if __name__ == "__main__":
    print(f"'11' (should be 3): {bin_to_oct('11')}")
